const p = msg.payload;

const required = ['type', 'schema_version', 'timestamp', 'site_id', 'smart_energy', 'smart_city'];
const missing = required.filter(f => p[f] === undefined);

if (missing.length > 0) {
    msg.statusCode = 400;
    msg.payload = { error: 'Missing fields: ' + missing.join(', ') };
    return [null, msg];
}

if (p.type !== 'sim.tick') {
    msg.statusCode = 400;
    msg.payload = { error: 'Invalid type: ' + p.type + ', expected sim.tick' };
    return [null, msg];
}

flow.set('last_tick', p.timestamp);
flow.set('tick_count', (flow.get('tick_count') || 0) + 1);

return [msg, null];

const envelope = msg.payload;
const ts = envelope.timestamp;
const siteId = envelope.site_id;

const msgs = [];

const meters = envelope.smart_energy.meters || [];
for (const m of meters) {
    msgs.push({ topic: 'sim.smart_energy.meter', key: m.meter_id || m.asset_id, payload: JSON.stringify(m) });
}

const pvs = envelope.smart_energy.pv || [];
for (const p of pvs) {
    msgs.push({ topic: 'sim.smart_energy.pv', key: p.pv_system_id || p.asset_id, payload: JSON.stringify(p) });
}

const weather = envelope.smart_energy.weather;
if (weather) {
    msgs.push({ topic: 'sim.smart_energy.weather', key: weather.site_id || siteId, payload: JSON.stringify(weather) });
}

const price = envelope.smart_energy.price;
if (price) {
    msgs.push({ topic: 'sim.smart_energy.price', key: 'price', payload: JSON.stringify(price) });
}

const consumers = envelope.smart_energy.consumers || [];
for (const c of consumers) {
    msgs.push({ topic: 'sim.smart_energy.consumer', key: c.device_id || c.asset_id, payload: JSON.stringify(c) });
}

const lights = envelope.smart_city.streetlights || [];
for (const l of lights) {
    msgs.push({ topic: 'sim.smart_city.light', key: l.light_id, payload: JSON.stringify(l) });
}

const traffic = envelope.smart_city.traffic_readings || [];
for (const t of traffic) {
    msgs.push({ topic: 'sim.smart_city.traffic', key: t.zone_id, payload: JSON.stringify(t) });
}

const events = envelope.smart_city.events || [];
for (const e of events) {
    msgs.push({ topic: 'sim.smart_city.event', key: e.zone_id, payload: JSON.stringify(e) });
}

const visibility = envelope.smart_city.visibility;
if (visibility) {
    msgs.push({ topic: 'sim.smart_city.weather', key: envelope.smart_city.city_id || 'city', payload: JSON.stringify(visibility) });
}

node.send([msgs]);

const response = {
    payload: { status: 'accepted', timestamp: ts, messages_queued: msgs.length, tick_count: flow.get('tick_count') || 0 },
    statusCode: 200,
    req: msg.req,
    res: msg.res
};

return [null, response];

const topicMap = {
    'sim.smart_energy.meter': 0,
    'sim.smart_energy.pv': 1,
    'sim.smart_energy.weather': 2,
    'sim.smart_energy.price': 3,
    'sim.smart_energy.consumer': 4,
    'sim.smart_city.light': 5,
    'sim.smart_city.traffic': 6,
    'sim.smart_city.event': 7,
    'sim.smart_city.weather': 8
};

const outputIndex = topicMap[msg.topic];
if (outputIndex !== undefined) {
    const outputs = new Array(9).fill(null);
    outputs[outputIndex] = msg;
    return outputs;
}

node.warn('Unknown topic: ' + msg.topic);
return null;
